def reshape_img(img):
    return img.reshape((-1, 3))

def apply_kmeans(n_clusters, random_state, data):
    if not isinstance(n_clusters, int) or n_clusters <= 0:
        raise ValueError("'n_clusters' should be a positive integer.")

    kmeans = KMeans(n_clusters=n_clusters, random_state=random_state)
    kmeans.fit(data)
    return kmeans

def get_labels(kmeans):
    return kmeans.labels_

def replace_colors(kmeans, labels, img_shape):
    segmented_img = kmeans.cluster_centers_[labels].reshape(img_shape)

    # Convert the image from float to int
    return segmented_img.astype(np.uint8)

def task_func(image_path='image.jpg', n_clusters=3, random_seed=42):
    img = read_image(image_path)

    # Reshape the image to be a list of RGB pixels
    img_reshape = reshape_img(img)

    # Apply KMeans clustering
    kmeans = apply_kmeans(n_clusters, random_seed, img_reshape)

    # Get the cluster labels for each pixel
    labels = get_labels(kmeans)

    # Replace each pixel's color with the centroid of the cluster it belongs to
    segmented_img = replace_colors(kmeans, labels, img.shape)

    return img, segmented_img

