import base64
from urllib.parse import quote
from codecs import encode as rot13

def task_func(hex_string):
    # Convert hexadecimal to bytes and UTF-8 string
    utf8_str = bytes.fromhex(hex_string).decode('utf-8')

    # Initialize dictionary with hexadecimal string
    encodings = {'hex': hex_string}

    for encoding in ['base64', 'utf-8', 'utf-16', 'utf-32', 'ascii', 'url', 'rot13']:
        if encoding == 'base64':
            encodings[encoding] = base64.b64encode(bytes.fromhex(hex_string)).decode('utf-8')
        elif encoding == 'utf-8':
            encodings[encoding] = utf8_str
        elif encoding == 'utf-16':
            encodings[encoding] = utf8_str.encode(encoding).decode(encoding)
        elif encoding == 'utf-32':
            encodings[encoding] = utf8_str.encode(encoding).decode(encoding)
        elif encoding == 'ascii':
            try:
                encodings[encoding] = utf8_str.encode('ascii').decode('ascii')
            except UnicodeEncodeError:
                encodings[encoding] = 'Not representable in ASCII'
        elif encoding == 'url':
            encodings[encoding] = quote(utf8_str)
        elif encoding == 'rot13':
            encodings[encoding] = rot13(utf8_str, 'rot_13')

    return encodings

