import re
from urllib.parse import urlparse
import ssl
import socket

def get_urls(my_string):
    # Regular expression pattern to match https URLs
    url_pattern = re.compile(r'https://[^\s]+')

    return url_pattern.findall(my_string)  # Extract all https URLs from the string

def get_domain(url):
    # Parse the URL to get the domain name
    return urlparse(url).netloc

def create_ssl_context():
    # Create a context for SSL verification with strict checking
    return ssl.create_default_context()

def get_certificate_expiry(domain, context):
    try:
        # Establish a socket connection to the domain on port 443
        with socket.create_connection((domain, 443)) as sock:
            # Wrap the socket in an SSL wrapper using the provided context and server hostname
            with context.wrap_socket(sock, server_hostname=domain) as ssock:
                cert = ssock.getpeercert()  # Get the SSL certificate from the socket

        return cert['notAfter'].replace(' GMT', ' UTC') if cert else None  # Extract and convert notAfter field to UTC format
    except (ConnectionRefusedError, ssl.SSLError):  
        pass  # Ignore any URLs that cause an SSL error or connection refusal

def task_func(my_string):

    urls = get_urls(my_string)

    ssl_info = {}
    context = create_ssl_context()

    for url in urls:
        domain = get_domain(url)

        not_after_utc = get_certificate_expiry(domain, context)

        if not_after_utc is not None:
            # Add the domain and its SSL certificate expiry date to the dictionary
            ssl_info[domain] = not_after_utc

    return ssl_info
